{
  "terms": [
    {
      "term": "Generation",
      "simpleDefinition": "The process of converting energy sources like gas, wind, or nuclear power into electrical energy.",
      "anchor": "The starting point of the electrical supply chain.",
      "misconception": "Thinking electricity is 'created' rather than converted from another energy source."
    },
    {
      "term": "Transmission",
      "simpleDefinition": "The bulk movement of electricity at very high voltages over long distances from power stations to the local network.",
      "anchor": "The 'motorway' of the electrical system.",
      "misconception": "Confusing transmission with distribution, which happens at lower voltages closer to the consumer."
    },
    {
      "term": "Transmission Voltages",
      "simpleDefinition": "The specific high-voltage levels used in the UK grid: 400 kV, 275 kV, and 132 kV.",
      "anchor": "400, 275, and 132.",
      "misconception": "Believing that 11 kV or 33 kV are transmission voltages; these are actually distribution voltages."
    },
    {
      "term": "Micro-generation",
      "simpleDefinition": "Small-scale production of electricity generated at or near the point of use, such as on a home or small business.",
      "anchor": "Local power for local use.",
      "misconception": "Assuming micro-generation is intended to power the entire national grid like a large power station."
    },
    {
      "term": "Photovoltaic (PV)",
      "simpleDefinition": "A method of generating electricity directly from sunlight using solar panels.",
      "anchor": "Solar power.",
      "misconception": "Thinking solar panels require heat to work; they actually require light (photons)."
    },
    {
      "term": "Biomass",
      "simpleDefinition": "Organic materials, such as wood pellets or plant waste, that are burned to produce electricity.",
      "anchor": "Fuel from living things.",
      "misconception": "Thinking biomass is a fossil fuel like coal."
    },
    {
      "term": "Step-up Transformer",
      "simpleDefinition": "A device used at power stations to increase voltage and decrease current for efficient transmission.",
      "anchor": "Boosting voltage for the long journey.",
      "misconception": "Thinking that increasing the voltage also increases the total power available."
    }
  ],
  "anchorPhrases": [
    "Transmission is the motorway of electricity.",
    "400kV, 275kV, and 132kV are the UK transmission voltages.",
    "High voltage reduces heat loss during travel.",
    "Micro-generation happens at the point of use.",
    "Generation is the conversion of energy into electricity."
  ],
  "misconceptionTargets": [
    "High voltage is used simply because it is 'stronger' rather than for efficiency reasons.",
    "Electricity is generated at the same 230V used in homes.",
    "11kV and 33kV are part of the transmission network.",
    "Renewable sources like wind are only for micro-generation and not large-scale supply."
  ]
}

{
  "teachChecks": [
    {
      "title": "The National Grid Supply Chain",
      "basicQuestions": [
        {
          "questionText": "What is the name of the first stage in the supply chain where energy is converted into electrical power?",
          "answerGuidance": [
            "Generation",
            "Electrical generation"
          ]
        },
        {
          "questionText": "Which network is used to move electricity over long distances from power stations to cities?",
          "answerGuidance": [
            "Transmission",
            "Transmission network"
          ]
        },
        {
          "questionText": "In the analogy of the electrical system, what type of road is the transmission network compared to?",
          "answerGuidance": [
            "Motorway",
            "High-voltage motorway"
          ]
        }
      ],
      "deeperQuestionText": "Why is a dedicated transmission network necessary rather than just connecting power stations directly to local houses using standard cables?",
      "deeperAnswerGuidance": [
        "Power stations are often far away from consumers",
        "Electricity must travel long distances efficiently",
        "It acts as a bulk movement system for massive amounts of power",
        "It provides the essential link between the source and local areas"
      ],
      "hint": "Think about the starting point and the 'motorway' used for long-distance travel."
    },
    {
      "title": "Transmission Voltage Levels",
      "basicQuestions": [
        {
          "questionText": "What does the abbreviation 'kV' stand for?",
          "answerGuidance": [
            "Kilovolts",
            "Kilo-volts"
          ]
        },
        {
          "questionText": "What is the highest specific transmission voltage used in the UK National Grid?",
          "answerGuidance": [
            "400 kV",
            "400,000 volts"
          ]
        },
        {
          "questionText": "What structures are used to carry transmission voltages across the countryside?",
          "answerGuidance": [
            "Pylons",
            "Steel pylons"
          ]
        }
      ],
      "deeperQuestionText": "If a technician identifies a line operating at 33 kV, why is this excluded from the transmission category in the UK?",
      "deeperAnswerGuidance": [
        "Transmission is strictly the highest-voltage part of the system",
        "33 kV is a distribution voltage",
        "Transmission voltages are specifically 132 kV, 275 kV, or 400 kV",
        "It is used for local delivery rather than the bulk motorway network"
      ],
      "hint": "Remember the three specific numbers: 400, 275, and 132."
    },
    {
      "title": "Large-Scale Generation Methods",
      "basicQuestions": [
        {
          "questionText": "What term describes the burning of organic materials like wood pellets to generate electricity?",
          "answerGuidance": [
            "Biomass"
          ]
        },
        {
          "questionText": "Which large-scale generation method uses falling water to produce power?",
          "answerGuidance": [
            "Hydro",
            "Hydroelectric"
          ]
        },
        {
          "questionText": "What is the primary purpose of large-scale generation methods in relation to the national grid?",
          "answerGuidance": [
            "Supply the entire national grid",
            "Meet the country's total demand",
            "Feed the transmission network"
          ]
        }
      ],
      "deeperQuestionText": "How does the role of a large-scale wind farm differ from a single domestic wind turbine in the context of the national supply chain?",
      "deeperAnswerGuidance": [
        "Large-scale wind farms feed directly into the transmission network",
        "They are designed to meet bulk national demand",
        "Domestic turbines are for local use or micro-generation",
        "Large-scale methods provide power for the whole country"
      ],
      "hint": "List the sources used by big power stations, including fossil fuels, nuclear, and large renewables."
    },
    {
      "title": "Micro-Generation and Local Supply",
      "basicQuestions": [
        {
          "questionText": "What term describes small-scale electricity production that happens at or near the point of use?",
          "answerGuidance": [
            "Micro-generation",
            "Micro generation"
          ]
        },
        {
          "questionText": "What does the abbreviation 'PV' stand for in the context of solar panels?",
          "answerGuidance": [
            "Photovoltaic"
          ]
        },
        {
          "questionText": "What specific form of energy do photovoltaic cells convert into voltage?",
          "answerGuidance": [
            "Light",
            "Photons",
            "Sunlight"
          ]
        }
      ],
      "deeperQuestionText": "How does installing a PV system on a house change that building's relationship with the national transmission grid?",
      "deeperAnswerGuidance": [
        "It reduces the building's reliance on the grid",
        "Electricity is produced exactly where it is needed",
        "It provides local power for a specific building",
        "The building uses its own generated voltage before importing from the grid"
      ],
      "hint": "Focus on small-scale systems like solar panels on a house roof."
    },
    {
      "title": "The Purpose of High Voltage Transmission",
      "basicQuestions": [
        {
          "questionText": "What device is used at a power station to increase voltage for transmission?",
          "answerGuidance": [
            "Step-up transformer",
            "Step up transformer"
          ]
        },
        {
          "questionText": "When voltage is increased for transmission, what happens to the level of current?",
          "answerGuidance": [
            "Decreases",
            "It is lowered",
            "Reduced"
          ]
        },
        {
          "questionText": "What specific type of energy waste is minimized by using high-voltage transmission?",
          "answerGuidance": [
            "Heat",
            "Heat loss",
            "Wasted heat"
          ]
        }
      ],
      "deeperQuestionText": "Why is reducing the current the most important factor when sending electricity across hundreds of miles of cable?",
      "deeperAnswerGuidance": [
        "Lower current reduces friction in the wires",
        "It significantly reduces energy lost as heat",
        "It allows the same amount of power to be delivered more efficiently",
        "It prevents the cables from wasting energy during the journey"
      ],
      "hint": "Think about how increasing voltage allows us to lower the current and stop the wires from getting too hot."
    }
  ]
}

{
  "guidedPractice": {
    "title": "Guided Practice: Transmission Voltage Identification",
    "objective": "Identify a standard UK transmission voltage and explain its efficiency benefit.",
    "retrievalTextLines": [
      "UK transmission voltages are standardized at 132 kV, 275 kV, and 400 kV.",
      "Stepping up voltage at the power station reduces the current flow.",
      "Lower current results in significantly less energy wasted as heat in the cables."
    ],
    "questionText": "A technician is inspecting a connection to a 132 kV overhead line. Explain why this specific voltage level is used for the transmission network rather than a lower distribution voltage.",
    "answerGuidance": [
      "132 kV is a standard UK transmission voltage used to reduce current, which minimizes heat loss during long-distance energy transport."
    ],
    "hint": "Recall the three specific UK transmission voltages and the relationship between high voltage, low current, and heat loss."
  },
  "practice": {
    "title": "Independent Practice: Transmission Efficiency",
    "objective": "Explain the technical relationship between transmission voltage and energy efficiency.",
    "retrievalTextLines": [
      "Transmission is the 'motorway' of the electrical system, moving bulk power over long distances.",
      "Efficiency is the primary driver for using extremely high voltages like 275 kV or 400 kV."
    ],
    "questionText": "Explain the primary technical reason why the National Grid uses step-up transformers to reach voltages such as 400 kV before transmitting electricity across the country.",
    "answerGuidance": [
      "Increasing the voltage allows for a lower current, which reduces the amount of energy lost as heat in the transmission lines."
    ],
    "hint": "Think about what happens to the current when voltage is stepped up and how that affects 'friction' or heat in the cables."
  }
}

{
  "integrative": {
    "title": "National Grid Connection Strategy",
    "objective": "Synthesize the relationship between large-scale generation, standard transmission voltages, and the physics of energy efficiency.",
    "retrievalTextLines": [
      "Large-scale generation sources, such as nuclear or wind farms, provide bulk power to the National Grid.",
      "UK transmission voltages are standardized at 132 kV, 275 kV, and 400 kV.",
      "Stepping up voltage at the source allows for a significant reduction in current.",
      "Reducing current is the primary method used to minimize energy wasted as heat over long distances."
    ],
    "questionText": "A new large-scale biomass power station is being connected to the UK pylon network to supply a city 150 miles away. Explain why the output must be stepped up to a specific transmission voltage (naming one standard UK value) and describe the technical advantage this provides for the long-distance journey.",
    "answerGuidance": [
      "The power must be stepped up to a standard UK transmission voltage such as 132 kV, 275 kV, or 400 kV.",
      "Stepping up the voltage reduces the current flowing through the transmission lines.",
      "Lowering the current minimizes energy loss caused by heat (resistance) in the cables, ensuring the electricity reaches the city efficiently."
    ],
    "hint": "Identify one of the three UK transmission voltages and explain how 'stepping up' affects current and heat loss."
  }
}

